// event type definitions:

export class OrderPlaced implements DcbEvent {
  public type = "orderPlaced" as const
  public tags: Tags
  public data: { orderId: string; idempotencyKey: string }

  constructor({ orderId, idempotencyKey }: { orderId: string; idempotencyKey: string }) {
    this.tags = Tags.from([`order:${orderId}`, `idempotency:${idempotencyKey}`])
    this.data = { orderId, idempotencyKey }
  }
}

// decision models:

export const IdempotencyKeyWasUsed = (idempotencyKey: string): EventHandlerWithState&lt;OrderPlaced, boolean&gt; =&gt; ({
  tagFilter: Tags.from([`idempotency:${idempotencyKey}`]),
  init: false,
  when: {
    orderPlaced: ({}) =&gt; true,
  },
})

// command handlers:

export class Api {
  private eventStore: EventStore
  constructor(eventStore: EventStore) {
      this.eventStore = eventStore
  }

  async placeOrder(command: { orderId: string; idempotencyKey: string }) {
    const { state, appendCondition } = await buildDecisionModel(this.eventStore, {
      idempotencyKeyWasUsed: IdempotencyKeyWasUsed(command.idempotencyKey),
    })
    if (state.idempotencyKeyWasUsed) throw new Error("Re-submission")
    await this.eventStore.append(
      new OrderPlaced({ orderId: command.orderId, idempotencyKey: command.idempotencyKey }),
      appendCondition
    )
  }
}
